## Goal

Implement the Web Worker that handles all cryptographic operations: Argon2id key derivation, DEK unwrapping, chunk download, AEAD decryption, and streaming decompression.

## Technical Approach

### crypto_worker.js

```javascript
// Import WASM modules
let argon2 = null;
let fflate = null;

// Initialize WASM on worker start
async function init() {
    argon2 = await import('./vendor/argon2-wasm.js');
    fflate = await import('./vendor/fflate.min.js');
}
init();

// Handle messages from main thread
self.onmessage = async (e) => {
    const { type, ...data } = e.data;

    switch (type) {
        case 'UNLOCK':
            await handleUnlock(data.password, data.config);
            break;
        case 'CANCEL':
            // Set abort flag
            break;
    }
};

async function handleUnlock(secret, config) {
    try {
        // Step 1: Unwrap DEK from key slots
        self.postMessage({ type: 'PROGRESS', phase: 'kdf', percent: 0 });
        const dek = await unlockDEK(secret, config);
        self.postMessage({ type: 'PROGRESS', phase: 'kdf', percent: 100 });

        // Step 2: Download, decrypt, decompress chunks
        self.postMessage({ type: 'PROGRESS', phase: 'decrypt', percent: 0 });
        const dbBytes = await downloadDecryptDecompress(config, dek);
        self.postMessage({ type: 'PROGRESS', phase: 'decrypt', percent: 100 });

        // Step 3: Store DB bytes (or write to OPFS)
        self.postMessage({ type: 'PROGRESS', phase: 'init', percent: 0 });
        await initializeDatabase(dbBytes);
        self.postMessage({ type: 'PROGRESS', phase: 'init', percent: 100 });

        self.postMessage({ type: 'UNLOCK_SUCCESS' });
    } catch (error) {
        self.postMessage({ type: 'UNLOCK_FAILED', error: error.message });
    }
}
```

### Step 1: DEK Unwrapping

```javascript
async function unlockDEK(secret, config) {
    const exportIdBytes = base64ToBytes(config.export_id);

    for (const slot of config.key_slots) {
        try {
            // Derive KEK based on slot type
            let kek;
            if (slot.kdf === 'argon2id') {
                kek = await argon2.hash({
                    pass: secret,
                    salt: base64ToBytes(slot.salt),
                    time: slot.kdf_params.iterations,
                    mem: slot.kdf_params.memory_kb,
                    parallelism: slot.kdf_params.parallelism,
                    hashLen: 32,
                    type: argon2.ArgonType.Argon2id,
                });
            } else if (slot.kdf === 'hkdf-sha256') {
                kek = await deriveHKDF(secret, slot.salt);
            }

            // Try unwrapping DEK
            const kekKey = await crypto.subtle.importKey(
                'raw', kek.hash, { name: 'AES-GCM' }, false, ['decrypt']
            );

            const aad = buildSlotAad(exportIdBytes, slot.id);
            const dekBuf = await crypto.subtle.decrypt(
                { name: 'AES-GCM', iv: base64ToBytes(slot.nonce), additionalData: aad },
                kekKey,
                base64ToBytes(slot.wrapped_dek)
            );

            return new Uint8Array(dekBuf);
        } catch (_) {
            // Auth tag mismatch → try next slot
            continue;
        }
    }

    throw new Error('Invalid password or recovery secret');
}
```

### Step 2: Streaming Decrypt + Decompress

```javascript
async function downloadDecryptDecompress(config, dekBytes) {
    const chunkFiles = config.payload.files;
    const total = chunkFiles.length;
    const exportIdBytes = base64ToBytes(config.export_id);
    const baseNonce = base64ToBytes(config.base_nonce);

    // Import DEK
    const dekKey = await crypto.subtle.importKey(
        'raw', dekBytes, { name: 'AES-GCM' }, false, ['decrypt']
    );

    // Collect decompressed chunks
    const decompressedChunks = [];
    const inflater = new fflate.Inflate((chunk, final) => {
        decompressedChunks.push(chunk);
    });

    for (let i = 0; i < total; i++) {
        // Fetch encrypted chunk
        const response = await fetch(chunkFiles[i]);
        const encryptedChunk = new Uint8Array(await response.arrayBuffer());

        // Derive per-chunk nonce
        const chunkNonce = deriveChunkNonce(baseNonce, i);
        const chunkAad = buildChunkAad(exportIdBytes, i, config.version);

        // Decrypt (AEAD verifies integrity)
        const compressedChunk = await crypto.subtle.decrypt(
            { name: 'AES-GCM', iv: chunkNonce, additionalData: chunkAad },
            dekKey,
            encryptedChunk
        );

        // Feed to decompressor
        inflater.push(new Uint8Array(compressedChunk), i === total - 1);

        // Report progress
        self.postMessage({ 
            type: 'PROGRESS', 
            phase: 'decrypt', 
            percent: Math.round(((i + 1) / total) * 100)
        });
    }

    // Concatenate decompressed chunks
    const totalSize = decompressedChunks.reduce((sum, c) => sum + c.length, 0);
    const dbBytes = new Uint8Array(totalSize);
    let offset = 0;
    for (const chunk of decompressedChunks) {
        dbBytes.set(chunk, offset);
        offset += chunk.length;
    }

    return dbBytes;
}
```

### Counter-Based Nonce Derivation

```javascript
function deriveChunkNonce(baseNonce, chunkIndex) {
    const nonce = new Uint8Array(12);
    nonce.set(baseNonce.slice(0, 8), 0);  // 8-byte prefix

    // counter_start from last 4 bytes of base_nonce
    const view = new DataView(baseNonce.buffer, baseNonce.byteOffset);
    const counterStart = view.getUint32(8, true);  // little-endian
    const counter = (counterStart + chunkIndex) >>> 0;  // mod 2^32

    new DataView(nonce.buffer).setUint32(8, counter, true);
    return nonce;
}
```

